-- =====================================================
-- Tables (one per Odoo model)
-- =====================================================

CREATE TABLE "_unknown" (
    "id" integer NOT NULL PRIMARY KEY,  -- Odoo primary key (serial in a real DB)
    "__last_update" timestamp,  -- Last Modified on [datetime]
    "display_name" varchar  -- Display Name [char]
);

CREATE TABLE "account_abstract_payment" (
    "id" integer NOT NULL PRIMARY KEY,  -- Odoo primary key (serial in a real DB)
    "__last_update" timestamp,  -- Last Modified on [datetime]
    "amount" numeric NOT NULL,  -- Payment Amount [monetary]
    "communication" varchar,  -- Memo [char]
    "currency_id" integer NOT NULL,  -- Currency [many2one]
    "display_name" varchar,  -- Display Name [char]
    "hide_payment_method" boolean,  -- Hide Payment Method [boolean]
    "journal_id" integer NOT NULL,  -- Payment Journal [many2one]
    "multi" boolean,  -- Multi [boolean]
    "partner_bank_account_id" integer,  -- Recipient Bank Account [many2one]
    "partner_id" integer,  -- Partner [many2one]
    "partner_type" varchar,  -- Partner Type [selection]
    "payment_date" date NOT NULL,  -- Payment Date [date]
    "payment_difference" numeric,  -- Payment Difference [monetary]
    "payment_difference_handling" varchar,  -- Payment Difference Handling [selection]
    "payment_method_code" varchar,  -- Code [char]
    "payment_method_id" integer NOT NULL,  -- Payment Method Type [many2one]
    "payment_type" varchar NOT NULL,  -- Payment Type [selection]
    "show_partner_bank_account" boolean,  -- Show Partner Bank Account [boolean]
    "writeoff_account_id" integer,  -- Difference Account [many2one]
    "writeoff_label" varchar  -- Journal Item Label [char]
);

CREATE TABLE "account_account" (
